#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
    int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline char Get(){char ch;do ch=getchar();while(ch^'A'&&ch^'Q');return ch;}
const int N=5e5+10;
int ch[N*30][2],cnt,s[N<<1],Rt[N<<1],tm[N*30];
inline void ins(int k,int pos)
{
    int p=Rt[pos]=++cnt;
    ch[p][0]=ch[Rt[pos-1]][0];ch[p][1]=ch[Rt[pos-1]][1];
    drep(24,0,i)
    {
        int &x=ch[p][(k>>i)&1];p=++cnt;
        x?(ch[p][0]=ch[x][0],ch[p][1]=ch[x][1]):(x=p);
        tm[x=p]=pos;
    }
}
inline int qry(int p,int lm,int x)
{
    int res=0;drep(24,0,i)
    {
        bool typ=(x>>i)&1;int l=ch[p][typ],r=ch[p][typ^1];
        if(r&&tm[r]>=lm)p=r,res^=(1<<i);else if(l&&tm[l]>=lm)p=l;else return res;
    }
    return res;
}
int main()
{
    int n=read(),m=read(),lst=0;
    rep(1,n,i)ins(s[i]=s[i-1]^read(),i);
    int l,r,z,tmp;rep(1,m,i)
    {
        switch(Get())
        {
            case 'A':   ++n;ins(s[n]=s[n-1]^read(),n);break;
            case 'Q':   l=read();r=read();tmp=qry(Rt[r-1],l-1,z=read()^s[n]);
                        printf("%d\n",l==1&&z>tmp?z:tmp);
        }
    }
    return 0;
}
